import React, { useState, useEffect } from 'react';
import axios from 'axios';
import './App.css';
import { marked } from 'marked';

const LANGUAGES = {
  en: { name: 'English', flag: '🇬🇧', code: 'en' },
  zh: { name: '中文', flag: '🇨🇳', code: 'zh' },
  es: { name: 'Español', flag: '🇪🇸', code: 'es' },
  fr: { name: 'Français', flag: '🇫🇷', code: 'fr' }
};

const AGENTS = {
  australia: [
    {
      company: "LearnStay.World",
      phone: "+61 413892060",
      email: "info@learnstay.world",
      website: "LearnStay.World"
    },
    {
      company: "Wealthskey Migration",
      name: "Ken Poon",
      registration: "2418441",
      phone: "+852 54867893",
      email: "admin@wealthskey.com",
      website: "https://wealthskey.com"
    }
  ],
  britain: [
    {
      company: "Wealthskey Migration",
      phone: "+852 54867893",
      email: "admin@wealthskey.com",
      website: "https://wealthskey.com"
    }
  ],
  canada: [
    {
      company: "LearnStay.World",
      phone: "+61 413892060",
      email: "info@learnstay.world",
      website: "LearnStay.World"
    },
    {
      company: "Wealthskey Migration",
      phone: "+852 54867893",
      email: "admin@wealthskey.com",
      website: "https://wealthskey.com"
    }
  ],
  usa: [
    {
      company: "Wealthskey Migration",
      phone: "+852 54867893",
      email: "admin@wealthskey.com",
      website: "https://wealthskey.com"
    }
  ]
};

function App() {
  const [input, setInput] = useState('');
  const [chatHistory, setChatHistory] = useState([]);
  const [uploadedFiles, setUploadedFiles] = useState([]);
  const [showFileUpload, setShowFileUpload] = useState(false);
  const [isLanguageDropdownOpen, setIsLanguageDropdownOpen] = useState(false);
  const [isProcessing, setIsProcessing] = useState(false);
  const [currentLanguage, setCurrentLanguage] = useState('en');
  const [showHybridPlanModal, setShowHybridPlanModal] = useState(false);
  const [showContactAgentModal, setShowContactAgentModal] = useState(false);
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [showAuthModal, setShowAuthModal] = useState(false);
  const [authTab, setAuthTab] = useState('login');
  const [showTools, setShowTools] = useState(true);
  const [useSerpApi, setUseSerpApi] = useState(false);
  const [tools, setTools] = useState([
    { name: 'Document Scanner', icon: 'fa-file-alt', active: false },
    { name: 'Visa Checker', icon: 'fa-passport', active: false },
    { name: 'Timeline Creator', icon: 'fa-calendar-alt', active: false },
    { name: 'Checklist Generator', icon: 'fa-tasks', active: false },
    { name: 'Cost Calculator', icon: 'fa-calculator', active: false }
  ]);
  const [activeTool, setActiveTool] = useState(null);

  useEffect(() => {
    const savedUseSerpApi = localStorage.getItem('useSerpApi') === 'true';
    setUseSerpApi(savedUseSerpApi);
  }, []);

  const addMessage = (role, content) => {
    const newMessage = {
      role,
      content,
      timestamp: new Date().toISOString()
    };
    setChatHistory(prev => [...prev, newMessage]);
  };

  const handleSendMessage = async () => {
    if (!input && uploadedFiles.length === 0) return;
    
    const userMessage = input;
    addMessage('user', userMessage);
    setInput('');
    setShowFileUpload(false);
    setIsProcessing(true);
    
    try {
      const formData = new FormData();
      formData.append('message', userMessage);
      formData.append('language', currentLanguage);
      formData.append('useSerpApi', useSerpApi);
      uploadedFiles.forEach(file => formData.append('files', file));

      const response = await axios.post('/api/chat', formData, {
        headers: {
          'Content-Type': 'multipart/form-data'
        }
      });

      addMessage('ai', response.data.response);
      setUploadedFiles([]);
    } catch (error) {
      console.error('Error sending message:', error);
      addMessage('ai', "Sorry, I encountered an error processing your request. Please try again later.");
    } finally {
      setIsProcessing(false);
    }
  };

  const handleFileSelect = (e) => {
    const files = Array.from(e.target.files).filter(file => file.size <= 5 * 1024 * 1024);
    if (files.length !== e.target.files.length) {
      alert('Some files were too large (max 5MB) and were not added.');
    }
    setUploadedFiles(prev => [...prev, ...files]);
    e.target.value = '';
  };

  const removeFile = (index) => {
    setUploadedFiles(prev => prev.filter((_, i) => i !== index));
  };

  const handleAuth = (type) => {
    if (type === 'login') {
      setIsAuthenticated(true);
      setShowAuthModal(false);
      addMessage('ai', "Welcome back! How can I assist with your immigration needs today?");
    } else {
      setIsAuthenticated(true);
      setShowAuthModal(false);
      addMessage('ai', "Welcome to AI-MMI! Let's get started with your immigration journey.");
    }
  };

  const logout = () => {
    setIsAuthenticated(false);
    addMessage('ai', "You have been logged out. Please log in again to access your profile.");
  };

  const selectPlan = (plan) => {
    if (!isAuthenticated) {
      setShowAuthModal(true);
      setShowHybridPlanModal(false);
      return;
    }
    
    const planNames = {
      'basic': 'Basic Plan',
      'premium': 'Premium Plan',
      'platinum': 'Platinum Plan'
    };
    
    alert(`Thank you for selecting the ${planNames[plan]}! You will be redirected to payment.`);
    setShowHybridPlanModal(false);
  };

  const contactAgent = (agentName) => {
    if (!isAuthenticated) {
      setShowAuthModal(true);
      setShowContactAgentModal(false);
      return;
    }
    
    alert(`Connecting you with ${agentName}...`);
  };

  const toggleTool = (index) => {
    const updatedTools = [...tools];
    updatedTools[index].active = !updatedTools[index].active;
    setTools(updatedTools);
    setActiveTool(updatedTools[index].active ? tools[index] : null);
  };

  const toggleSerpApi = () => {
    const newValue = !useSerpApi;
    setUseSerpApi(newValue);
    localStorage.setItem('useSerpApi', newValue.toString());
  };

  return (
    <div className="app-container">
      <header className="header">
        <div className="header-brand">
          <img 
            src="https://i.ibb.co/pjR8wxhR/ai-mmi-logo-dark-background.png" 
            alt="AI-MMI Logo" 
            className="header-icon" 
          />
          <h1 className="header-title">AI-MMI</h1>
        </div>
        
        <div className="header-controls">
          <div className="language-dropdown">
            <img 
              src="https://i.ibb.co/tMDdT4bd/icon-lang.png" 
              alt="Language" 
              className="header-icon" 
              onClick={() => setIsLanguageDropdownOpen(!isLanguageDropdownOpen)}
            />
            {isLanguageDropdownOpen && (
              <div className="language-options">
                {Object.values(LANGUAGES).map(lang => (
                  <button
                    key={lang.code}
                    onClick={() => {
                      setCurrentLanguage(lang.code);
                      setIsLanguageDropdownOpen(false);
                    }}
                    className={currentLanguage === lang.code ? 'active' : ''}
                  >
                    {lang.flag} {lang.name}
                  </button>
                ))}
              </div>
            )}
          </div>
          <img 
            src={isAuthenticated ? "https://i.imgur.com/FcJiNT7.png" : "https://i.ibb.co/3mmnZvWc/icon-member.png"} 
            alt="User" 
            className="header-icon" 
            onClick={() => isAuthenticated ? logout() : setShowAuthModal(true)}
          />
          <img 
            src="https://i.ibb.co/NdFXvqSk/icon-menu.png" 
            alt="Tools" 
            className="header-icon" 
            onClick={() => setShowTools(!showTools)}
          />
        </div>
      </header>

      <div className="main-content">
        <div className="sidebar">
          <div className="sidebar-container">
            <div className="promo-banner">
              <button 
                className="btn-custom" 
                onClick={() => setShowContactAgentModal(true)}
              >
                Contact a Migration Lawyer/Agent
              </button>
            </div>
            
            <button className="sidebar-item">
              <span className="sidebar-icon"></span> Free assessment
            </button>
            <button className="sidebar-item">
              <span className="sidebar-icon"></span> Search chats
            </button>
            <button className="sidebar-item">
              <span className="sidebar-icon"></span> My profile
            </button>
            <button className="sidebar-item">
              <span className="sidebar-icon"></span> My documents
            </button>
            <button className="sidebar-item">
              <span className="sidebar-icon"></span> AI-MMI's recommendations
            </button>
            
            <div className="promo-banner">
              <button 
                className="btn-custom" 
                onClick={() => setShowHybridPlanModal(true)}
              >
                Subscribe for Hybrid Plan
              </button>
            </div>
          </div>
        </div>

        <div className="chat-container">
          <div className="chat-history">
            {chatHistory.length === 0 ? (
              <div className="welcome-message">
                <h2>Welcome to AI-MMI Immigration Assistant</h2>
                <p>Ask me anything about visas, immigration processes, or upload your documents for analysis.</p>
                <p>Current language: {LANGUAGES[currentLanguage].flag} {LANGUAGES[currentLanguage].name}</p>
              </div>
            ) : (
              chatHistory.map((msg, index) => (
                <div key={index} className={`message ${msg.role}-message`}>
                  <div dangerouslySetInnerHTML={{ __html: marked.parse(msg.content) }} />
                  <div className="timestamp">
                    {new Date(msg.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                  </div>
                </div>
              ))
            )}
            {isProcessing && (
              <div className="message ai-message">
                <div className="text-center">
                  <div className="spinner-border spinner-border-sm" role="status"></div> Processing...
                </div>
              </div>
            )}
          </div>
          
          <div className="input-area">
            <div className="search-toggle">
              <label>
                <input 
                  type="checkbox" 
                  checked={useSerpApi} 
                  onChange={toggleSerpApi} 
                />
                Include web search results
              </label>
            </div>
            
            {showFileUpload && (
              <div className="file-upload-container">
                <div className="file-previews">
                  {uploadedFiles.map((file, index) => (
                    <div key={index} className="file-preview">
                      <i className={`fas ${
                        file.type === 'application/pdf' ? 'fa-file-pdf' :
                        file.type.includes('word') ? 'fa-file-word' :
                        file.type === 'text/plain' ? 'fa-file-alt' :
                        file.type.includes('image') ? 'fa-file-image' : 'fa-file'
                      } file-icon`}></i>
                      <span className="file-name">{file.name}</span>
                      <button 
                        className="remove-file-btn"
                        onClick={() => removeFile(index)}
                      >
                        <i className="fas fa-times"></i>
                      </button>
                    </div>
                  ))}
                </div>
                <label htmlFor="fileUpload" className="btn-custom-outline">
                  <i className="fas fa-plus"></i> Add Files
                </label>
                <input 
                  type="file" 
                  id="fileUpload" 
                  multiple 
                  style={{ display: 'none' }} 
                  onChange={handleFileSelect}
                  accept=".pdf,.doc,.docx,.txt,.png,.jpg,.jpeg"
                />
                <p className="file-upload-note">Supported: PDF, Word, TXT, PNG, JPG (Max 5MB each)</p>
              </div>
            )}
            
            <div className="input-group">
              <button 
                className="btn-custom-outline attachment-btn" 
                onClick={() => setShowFileUpload(!showFileUpload)}
              >
                <i className="fas fa-paperclip"></i>
              </button>
              <textarea
                className="chat-input"
                value={input}
                onChange={(e) => setInput(e.target.value)}
                onKeyDown={(e) => {
                  if (e.key === 'Enter' && !e.shiftKey) {
                    e.preventDefault();
                    handleSendMessage();
                  }
                }}
                placeholder={`Type your question in ${LANGUAGES[currentLanguage].name}...`}
                rows={3}
              />
              <button 
                className="btn-custom send-btn" 
                onClick={handleSendMessage}
                disabled={(!input && uploadedFiles.length === 0) || isProcessing}
              >
                <i className="fas fa-paper-plane"></i>
              </button>
            </div>
          </div>
        </div>

        {showTools && (
          <div className="tools-panel">
            <div className="tools-header">
              <h3>Tools</h3>
              <button 
                className="close-tools" 
                onClick={() => setShowTools(false)}
              >
                <i className="fas fa-times"></i>
              </button>
            </div>
            <div className="tools-list">
              {tools.map((tool, index) => (
                <button
                  key={index}
                  className={`tool-item ${tool.active ? 'active' : ''}`}
                  onClick={() => toggleTool(index)}
                >
                  <i className={`fas ${tool.icon}`}></i>
                  {tool.name}
                </button>
              ))}
            </div>
            {activeTool && (
              <div className="tool-content">
                <h4>{activeTool.name}</h4>
                {activeTool.name === 'Document Scanner' && (
                  <div className="tool-details">
                    <p>Scan and analyze your immigration documents for completeness and accuracy.</p>
                    <button className="btn-custom-outline">
                      <i className="fas fa-upload"></i> Upload Document
                    </button>
                  </div>
                )}
                {activeTool.name === 'Visa Checker' && (
                  <div className="tool-details">
                    <p>Check your eligibility for different visa types based on your profile.</p>
                    <button className="btn-custom-outline">
                      <i className="fas fa-question-circle"></i> Check Eligibility
                    </button>
                  </div>
                )}
                {activeTool.name === 'Timeline Creator' && (
                  <div className="tool-details">
                    <p>Create a personalized timeline for your immigration process.</p>
                    <button className="btn-custom-outline">
                      <i className="fas fa-plus"></i> Create Timeline
                    </button>
                  </div>
                )}
                {activeTool.name === 'Checklist Generator' && (
                  <div className="tool-details">
                    <p>Generate a customized checklist for your immigration application.</p>
                    <button className="btn-custom-outline">
                      <i className="fas fa-list"></i> Generate Checklist
                    </button>
                  </div>
                )}
                {activeTool.name === 'Cost Calculator' && (
                  <div className="tool-details">
                    <p>Estimate the total costs for your immigration process.</p>
                    <button className="btn-custom-outline">
                      <i className="fas fa-calculator"></i> Calculate Costs
                    </button>
                  </div>
                )}
              </div>
            )}
          </div>
        )}
      </div>

      {showHybridPlanModal && (
        <div className="modal-overlay">
          <div className="hybrid-plan-container">
            <div className="hybrid-plan-header">
              <h2>Choose Your Hybrid Plan</h2>
              <button className="hybrid-plan-close" onClick={() => setShowHybridPlanModal(false)}>
                &times;
              </button>
            </div>
            <div className="hybrid-plan-body">
              <p>Upgrade to a Hybrid Plan to get the best of both worlds - AI assistance combined with expert human support for your immigration needs.</p>
              
              <div className="plan-cards">
                <div className="plan-card plan-card-basic">
                  <div className="plan-card-header">
                    <h3>Basic Plan</h3>
                    <p>For simple immigration queries</p>
                  </div>
                  <div className="plan-card-body">
                    <ul className="plan-features">
                      <li><i className="fas fa-check"></i> Unlimited AI chat assistance</li>
                      <li><i className="fas fa-check"></i> Document analysis (up to 5/month)</li>
                      <li><i className="fas fa-check"></i> Basic visa eligibility check</li>
                      <li><i className="fas fa-check"></i> Email support (72h response)</li>
                      <li><i className="fas fa-times"></i> No human agent access</li>
                    </ul>
                    <div className="plan-price">
                      $9.99 <span>/ month</span>
                    </div>
                    <button className="plan-select-btn" onClick={() => selectPlan('basic')}>
                      Select Basic Plan
                    </button>
                  </div>
                </div>
                
                <div className="plan-card plan-card-premium">
                  <div className="plan-card-header">
                    <h3>Premium Plan</h3>
                    <p>Most popular choice</p>
                  </div>
                  <div className="plan-card-body">
                    <ul className="plan-features">
                      <li><i className="fas fa-check"></i> Everything in Basic</li>
                      <li><i className="fas fa-check"></i> Priority AI responses</li>
                      <li><i className="fas fa-check"></i> Document analysis (unlimited)</li>
                      <li><i className="fas fa-check"></i> 2 consultations with agent/month</li>
                      <li><i className="fas fa-check"></i> Email support (24h response)</li>
                    </ul>
                    <div className="plan-price">
                      $29.99 <span>/ month</span>
                    </div>
                    <button className="plan-select-btn" onClick={() => selectPlan('premium')}>
                      Select Premium Plan
                    </button>
                  </div>
                </div>
                
                <div className="plan-card plan-card-platinum">
                  <div className="plan-card-header">
                    <h3>Platinum Plan</h3>
                    <p>For complex cases</p>
                  </div>
                  <div className="plan-card-body">
                    <ul className="plan-features">
                      <li><i className="fas fa-check"></i> Everything in Premium</li>
                      <li><i className="fas fa-check"></i> Unlimited agent consultations</li>
                      <li><i className="fas fa-check"></i> Document review by agents</li>
                      <li><i className="fas fa-check"></i> Application preparation help</li>
                      <li><i className="fas fa-check"></i> Priority 24/7 support</li>
                    </ul>
                    <div className="plan-price">
                      $99.99 <span>/ month</span>
                    </div>
                    <button className="plan-select-btn" onClick={() => selectPlan('platinum')}>
                      Select Platinum Plan
                    </button>
                  </div>
                </div>
              </div>
              
              <div className="hybrid-plan-footer">
                <p>All plans come with a 7-day money back guarantee. Cancel anytime.</p>
                <button className="back-to-home" onClick={() => setShowHybridPlanModal(false)}>
                  <i className="fas fa-arrow-left"></i> Back to Home
                </button>
              </div>
            </div>
          </div>
        </div>
      )}

      {showContactAgentModal && (
        <div className="modal-overlay">
          <div className="contact-agent-container">
            <div className="contact-agent-header">
              <h2>Contact a Migration Expert</h2>
              <button className="contact-agent-close" onClick={() => setShowContactAgentModal(false)}>
                &times;
              </button>
            </div>
            <div className="contact-agent-body">
              <p>Connect with our network of registered migration agents and lawyers for personalized assistance with your case.</p>
              
              <div className="country-section">
                <h3 className="country-title">Australia</h3>
                <div className="agent-cards">
                  {AGENTS.australia.map((agent, index) => (
                    <div key={`aus-${index}`} className="agent-card">
                      <div className="agent-card-header">
                        <h4 className="agent-company">{agent.company}</h4>
                      </div>
                      <div className="agent-card-body">
                        <div className="agent-details">
                          <p><i className="fas fa-phone"></i> {agent.phone}</p>
                          <p><i className="fas fa-envelope"></i> {agent.email}</p>
                          <p><i className="fas fa-globe"></i> {agent.website}</p>
                        </div>
                        {agent.name && (
                          <div style={{ marginTop: '10px' }}>
                            <p className="agent-name">{agent.name}</p>
                            {agent.registration && (
                              <p className="agent-registration">Registration: {agent.registration}</p>
                            )}
                          </div>
                        )}
                        <button 
                          className="agent-contact-btn" 
                          onClick={() => contactAgent(agent.company)}
                        >
                          Contact Agent
                        </button>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
              
              <div className="country-section">
                <h3 className="country-title">Britain</h3>
                <div className="agent-cards">
                  {AGENTS.britain.map((agent, index) => (
                    <div key={`uk-${index}`} className="agent-card">
                      <div className="agent-card-header">
                        <h4 className="agent-company">{agent.company}</h4>
                      </div>
                      <div className="agent-card-body">
                        <div className="agent-details">
                          <p><i className="fas fa-phone"></i> {agent.phone}</p>
                          <p><i className="fas fa-envelope"></i> {agent.email}</p>
                          <p><i className="fas fa-globe"></i> {agent.website}</p>
                        </div>
                        <button 
                          className="agent-contact-btn" 
                          onClick={() => contactAgent(agent.company)}
                        >
                          Contact Agent
                        </button>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
              
              <div className="country-section">
                <h3 className="country-title">Canada</h3>
                <div className="agent-cards">
                  {AGENTS.canada.map((agent, index) => (
                    <div key={`ca-${index}`} className="agent-card">
                      <div className="agent-card-header">
                        <h4 className="agent-company">{agent.company}</h4>
                      </div>
                      <div className="agent-card-body">
                        <div className="agent-details">
                          <p><i className="fas fa-phone"></i> {agent.phone}</p>
                          <p><i className="fas fa-envelope"></i> {agent.email}</p>
                          <p><i className="fas fa-globe"></i> {agent.website}</p>
                        </div>
                        <button 
                          className="agent-contact-btn" 
                          onClick={() => contactAgent(agent.company)}
                        >
                          Contact Agent
                        </button>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
              
              <div className="country-section">
                <h3 className="country-title">United States</h3>
                <div className="agent-cards">
                  {AGENTS.usa.map((agent, index) => (
                    <div key={`us-${index}`} className="agent-card">
                      <div className="agent-card-header">
                        <h4 className="agent-company">{agent.company}</h4>
                      </div>
                      <div className="agent-card-body">
                        <div className="agent-details">
                          <p><i className="fas fa-phone"></i> {agent.phone}</p>
                          <p><i className="fas fa-envelope"></i> {agent.email}</p>
                          <p><i className="fas fa-globe"></i> {agent.website}</p>
                        </div>
                        <button 
                          className="agent-contact-btn" 
                          onClick={() => contactAgent(agent.company)}
                        >
                          Contact Agent
                        </button>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
              
              <div className="contact-agent-footer">
                <p>All our agents are registered with the appropriate regulatory bodies in their jurisdictions.</p>
                <button className="back-to-home" onClick={() => setShowContactAgentModal(false)}>
                  <i className="fas fa-arrow-left"></i> Back to Home
                </button>
              </div>
            </div>
          </div>
        </div>
      )}

      {showAuthModal && (
        <div className="modal-overlay">
          <div className="auth-modal">
            <div className="auth-tabs">
              <div 
                className={`auth-tab ${authTab === 'login' ? 'active' : ''}`} 
                onClick={() => setAuthTab('login')}
              >
                Login
              </div>
              <div 
                className={`auth-tab ${authTab === 'signup' ? 'active' : ''}`} 
                onClick={() => setAuthTab('signup')}
              >
                Sign Up
              </div>
            </div>
            
            {authTab === 'login' ? (
              <div className="auth-form active">
                <div className="form-group">
                  <label htmlFor="loginEmail">Email</label>
                  <input type="email" id="loginEmail" placeholder="Enter your email" />
                </div>
                <div className="form-group">
                  <label htmlFor="loginPassword">Password</label>
                  <input type="password" id="loginPassword" placeholder="Enter your password" />
                </div>
                <div className="auth-actions">
                  <button className="btn-custom-outline" onClick={() => setShowAuthModal(false)}>
                    Cancel
                  </button>
                  <button className="btn-custom" onClick={() => handleAuth('login')}>
                    Login
                  </button>
                </div>
              </div>
            ) : (
              <div className="auth-form active">
                <div className="form-group">
                  <label htmlFor="signupName">Full Name</label>
                  <input type="text" id="signupName" placeholder="Enter your full name" />
                </div>
                <div className="form-group">
                  <label htmlFor="signupEmail">Email</label>
                  <input type="email" id="signupEmail" placeholder="Enter your email" />
                </div>
                <div className="form-group">
                  <label htmlFor="signupPassword">Password</label>
                  <input type="password" id="signupPassword" placeholder="Create a password" />
                </div>
                <div className="form-group">
                  <label htmlFor="signupConfirmPassword">Confirm Password</label>
                  <input 
                    type="password" 
                    id="signupConfirmPassword" 
                    placeholder="Confirm your password" 
                  />
                </div>
                <div className="auth-actions">
                  <button className="btn-custom-outline" onClick={() => setShowAuthModal(false)}>
                    Cancel
                  </button>
                  <button className="btn-custom" onClick={() => handleAuth('signup')}>
                    Sign Up
                  </button>
                </div>
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
}

export default App;
